return await (async function(eda) {
  const fixtureName = '__codex_example___DMT_Schematic_getSchematicInfo_' + Date.now();
  const currentProject = await eda.dmt_Project.getCurrentProjectInfo();
  if (!currentProject) { throw new Error('当前没有打开工程，先打开一个工程再运行这个案例。'); }
  const schematics = await eda.dmt_Schematic.getAllSchematicsInfo();
  const schematicUuid = schematics?.[0]?.uuid;
  const result = await eda.dmt_Schematic.getSchematicInfo(schematicUuid);
  return {
    fixtureName,
    currentProject: currentProject?.friendlyName ?? currentProject?.name ?? currentProject?.uuid ?? null,
    result,
  };
})(eda);
